export const takeQuizPage = (quiz: Quiz, session: QuizSession, selectedAnswer?: number) => {
  const q = quiz.questions[session.currentIndex]
  const progress = ((session.currentIndex) / quiz.questions.length) * 100
  const isLast = session.currentIndex === quiz.questions.length - 1

  return h('div', { style: styles.page },
    h('a', { href: '/quizzes', style: { ...styles.link, fontSize: '14px' } }, '\u2190 Back to quizzes'),
    h('h1', { style: { ...styles.heading, ...styles.mt16 } }, quiz.title),
    h('div', { style: styles.progressBar },
      h('div', { style: styles.progressFill(progress) }),
    ),
    h('p', { style: styles.muted },
      `Question ${session.currentIndex + 1} of ${quiz.questions.length}`,
    ),
    h('div', { style: { ...styles.card, padding: '20px' } },
      h('h2', { style: { fontSize: '18px', fontWeight: '600', marginTop: 0, marginBottom: '16px' } }, q.text),
      h('form', { method: 'POST', action: `/quizzes/${quiz.id}/answer` },
        ...q.options.map((opt, i) =>
          h('div', { style: { marginBottom: '8px' } },
            h('label', {
              style: selectedAnswer === i ? styles.radioLabelSelected : styles.radioLabel,
            },
              h('input', {
                type: 'radio',
                name: 'answer',
                value: String(i),
                required: true,
                ...(selectedAnswer === i ? { checked: true } : {}),
              }),
              h('span', {}, opt.text),
            ),
          ),
        ),
        h('div', { style: styles.mt16 },
          h('button', { type: 'submit', style: styles.button },
            isLast ? 'Finish Quiz' : 'Next',
          ),
        ),
      ),
    ),
  )
}

export const resultsPage = (result: ScoreResult, quizId: string) => {
  const pct = Math.round((result.correct / result.total) * 100)

  return h('div', { style: styles.page },
    h('a', { href: '/quizzes', style: { ...styles.link, fontSize: '14px' } }, '\u2190 Back to quizzes'),
    h('h1', { style: { ...styles.heading, ...styles.mt16 } }, `Results: ${result.quizTitle}`),
    h('div', { style: styles.scoreBox },
      h('div', { style: styles.scoreNumber }, `${result.correct}/${result.total}`),
      h('p', { style: { ...styles.muted, margin: '8px 0 0' } }, `${pct}% correct`),
    ),
    h('h2', { style: styles.subheading }, 'Question Breakdown'),
    ...result.breakdown.map((item, i) =>
      h('div', { style: item.correct ? styles.questionCorrect : styles.questionIncorrect },
        h('div', { style: styles.spaceBetween },
          h('strong', {}, `${i + 1}. ${item.questionText}`),
          h('span', { style: item.correct ? styles.correct : styles.incorrect },
            item.correct ? '\u2713 Correct' : '\u2717 Incorrect',
          ),
        ),
        !item.correct
          ? h('p', { style: { margin: '8px 0 0', fontSize: '14px' } },
              h('span', { style: styles.incorrect },
                item.selectedIndex !== null
                  ? `Your answer: Option ${String.fromCharCode(65 + item.selectedIndex)}`
                  : 'No answer selected',
              ),
              ' \u2014 ',
              h('span', { style: styles.correct },
                `Correct: Option ${String.fromCharCode(65 + item.correctIndex)}`,
              ),
            )
          : null,
      ),
    ),
    h('div', { style: { ...styles.flex, ...styles.mt16 } },
      h('a', { href: `/quizzes/${quizId}/take`, style: styles.button }, 'Retake Quiz'),
      h('a', { href: '/quizzes', style: styles.buttonSecondary }, 'All Quizzes'),
    ),
  )
}

import { createSSR } from 'plaited'
import { getAllQuizzes, getQuizById, saveQuiz, deleteQuiz } from './store'
import { quizListPage, createQuizPage, takeQuizPage, resultsPage } from './templates'
import type { Quiz, Question, Option, QuizSession, ScoreResult, QuestionResult } from './types'

const sessions = new Map<string, QuizSession>()

const generateId = (): string =>
  Math.random().toString(36).slice(2, 10) + Date.now().toString(36)

const renderHtml = (content: ReturnType<typeof quizListPage>): string => {
  const { head, body } = createSSR()
  const bodyContent = body(content)
  const headContent = head()
  return `<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Quiz Builder</title>
${headContent}
</head>
<body>${bodyContent}</body>
</html>`
}

const htmlResponse = (content: ReturnType<typeof quizListPage>, status = 200): Response =>
  new Response(renderHtml(content), {
    status,
    headers: { 'Content-Type': 'text/html; charset=utf-8' },
  })

const redirect = (path: string): Response =>
  new Response(null, { status: 302, headers: { Location: path } })

const parseFormData = async (req: Request): Promise<Map<string, string>> => {
  const text = await req.text()
  const params = new URLSearchParams(text)
  const map = new Map<string, string>()
  for (const [key, value] of params) {
    map.set(key, value)
  }
  return map
}

const parseQuestionsFromForm = (form: Map<string, string>): Question[] => {
  const questions: Question[] = []
  let i = 0
  while (form.has(`q_${i}_text`)) {
    const text = form.get(`q_${i}_text`) ?? ''
    const options: [Option, Option, Option, Option] = [
      { text: form.get(`q_${i}_opt_0`) ?? '' },
      { text: form.get(`q_${i}_opt_1`) ?? '' },
      { text: form.get(`q_${i}_opt_2`) ?? '' },
      { text: form.get(`q_${i}_opt_3`) ?? '' },
    ]
    const correctIndex = parseInt(form.get(`q_${i}_correct`) ?? '0', 10)
    questions.push({ text, options, correctIndex })
    i++
  }
  return questions
}

const getSessionKey = (req: Request, quizId: string): string => {
  const ip = req.headers.get('x-forwarded-for') ?? 'local'
  return `${ip}:${quizId}`
}

const handleRequest = async (req: Request): Promise<Response> => {
  const url = new URL(req.url)
  const path = url.pathname
  const method = req.method

  // Root redirect
  if (path === '/') {
    return redirect('/quizzes')
  }

  // List quizzes
  if (path === '/quizzes' && method === 'GET') {
    const quizzes = await getAllQuizzes()
    return htmlResponse(quizListPage(quizzes))
  }

  // New quiz form
  if (path === '/quizzes/new' && method === 'GET') {
    return htmlResponse(createQuizPage())
  }

  // Create quiz
  if (path === '/quizzes' && method === 'POST') {
    const form = await parseFormData(req)
    const title = form.get('title')?.trim()
    if (!title) {
      return htmlResponse(createQuizPage('Quiz title is required.'), 400)
    }
    const questions = parseQuestionsFromForm(form)
    if (questions.length === 0) {
      return htmlResponse(createQuizPage('At least one question is required.'), 400)
    }
    const quiz: Quiz = {
      id: generateId(),
      title,
      questions,
      createdAt: new Date().toISOString(),
    }
    await saveQuiz(quiz)
    return redirect('/quizzes')
  }

  // Delete quiz
  const deleteMatch = path.match(/^\/quizzes\/([^/]+)\/delete$/)
  if (deleteMatch && method === 'POST') {
    await deleteQuiz(deleteMatch[1])
    return redirect('/quizzes')
  }

  // Take quiz - start or show current question
  const takeMatch = path.match(/^\/quizzes\/([^/]+)\/take$/)
  if (takeMatch && method === 'GET') {
    const quizId = takeMatch[1]
    const quiz = await getQuizById(quizId)
    if (!quiz) return redirect('/quizzes')

    const sessionKey = getSessionKey(req, quizId)
    const session: QuizSession = {
      quizId,
      currentIndex: 0,
      answers: new Array(quiz.questions.length).fill(null),
    }
    sessions.set(sessionKey, session)

    return htmlResponse(takeQuizPage(quiz, session))
  }

  // Submit answer
  const answerMatch = path.match(/^\/quizzes\/([^/]+)\/answer$/)
  if (answerMatch && method === 'POST') {
    const quizId = answerMatch[1]
    const quiz = await getQuizById(quizId)
    if (!quiz) return redirect('/quizzes')

    const sessionKey = getSessionKey(req, quizId)
    const session = sessions.get(sessionKey)
    if (!session) return redirect(`/quizzes/${quizId}/take`)

    const form = await parseFormData(req)
    const answer = parseInt(form.get('answer') ?? '-1', 10)
    session.answers[session.currentIndex] = answer

    if (session.currentIndex < quiz.questions.length - 1) {
      session.currentIndex++
      sessions.set(sessionKey, session)
      return htmlResponse(takeQuizPage(quiz, session))
    }

    // Last question answered — redirect to results
    sessions.set(sessionKey, session)
    return redirect(`/quizzes/${quizId}/results`)
  }

  // Results
  const resultsMatch = path.match(/^\/quizzes\/([^/]+)\/results$/)
  if (resultsMatch && method === 'GET') {
    const quizId = resultsMatch[1]
    const quiz = await getQuizById(quizId)
    if (!quiz) return redirect('/quizzes')

    const sessionKey = getSessionKey(req, quizId)
    const session = sessions.get(sessionKey)
    if (!session) return redirect(`/quizzes/${quizId}/take`)

    const breakdown: QuestionResult[] = quiz.questions.map((q, i) => {
      const selected = session.answers[i]
      return {
        questionText: q.text,
        selectedIndex: selected,
        correctIndex: q.correctIndex,
        correct: selected === q.correctIndex,
      }
    })

    const correctCount = breakdown.filter((b) => b.correct).length
    const scoreResult: ScoreResult = {
      quizTitle: quiz.title,
      total: quiz.questions.length,
      correct: correctCount,
      breakdown,
    }

    sessions.delete(sessionKey)
    return htmlResponse(resultsPage(scoreResult, quizId))
  }

  // API: list quizzes as JSON
  if (path === '/api/quizzes' && method === 'GET') {
    const quizzes = await getAllQuizzes()
    return new Response(JSON.stringify(quizzes), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  // API: create quiz as JSON
  if (path === '/api/quizzes' && method === 'POST') {
    const body = (await req.json()) as { title: string; questions: Question[] }
    const quiz: Quiz = {
      id: generateId(),
      title: body.title,
      questions: body.questions,
      createdAt: new Date().toISOString(),
    }
    await saveQuiz(quiz)
    return new Response(JSON.stringify(quiz), {
      status: 201,
      headers: { 'Content-Type': 'application/json' },
    })
  }

  // API: get single quiz
  const apiQuizMatch = path.match(/^\/api\/quizzes\/([^/]+)$/)
  if (apiQuizMatch && method === 'GET') {
    const quiz = await getQuizById(apiQuizMatch[1])
    if (!quiz) {
      return new Response(JSON.stringify({ error: 'Not found' }), {
        status: 404,
        headers: { 'Content-Type': 'application/json' },
      })
    }
    return new Response(JSON.stringify(quiz), {
      headers: { 'Content-Type': 'application/json' },
    })
  }

  return new Response('Not Found', { status: 404 })
}

export default {
  port: 3000,
  fetch: handleRequest,
}
